import React, { useState } from 'react';
import './Login.css';

const Login = () => {
  const [formData, setFormData] = useState({
    email: '',
    password: ''
  });

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    // Simple authentication - in a real app, this would validate against a backend
    if (formData.email && formData.password) {
      localStorage.setItem('isAuthenticated', 'true');
      // In a real app, you'd also store user info, tokens, etc.
      console.log('Login successful:', formData);
      // The router will automatically redirect to dashboard
      window.location.href = '/dashboard';
    } else {
      alert('Please enter both email and password');
    }
  };

  return (
    <div className="login-container">
      <div className="login-form">
        <h2>AI Productivity App</h2>
        <h3>Login</h3>
        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label htmlFor="email">Email</label>
            <input
              type="email"
              id="email"
              name="email"
              value={formData.email}
              onChange={handleChange}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="password">Password</label>
            <input
              type="password"
              id="password"
              name="password"
              value={formData.password}
              onChange={handleChange}
              required
            />
          </div>
          <button type="submit" className="login-btn">Login</button>
        </form>
      </div>
    </div>
  );
};

export default Login;
